const fs = require("fs");
const path = require("path");

const root = path.join(__dirname, "..");
const sourceDir = path.join(root, "vendor", "chinese-days", "years");
const years = {};

for (const name of fs.readdirSync(sourceDir).filter(name => /^\d{4}\.json$/.test(name)).sort()) {
    years[name.slice(0, 4)] = JSON.parse(fs.readFileSync(path.join(sourceDir, name), "utf8"));
}

const output = `/* Generated by tools/build-calendar-bundle.js. */\nwindow.RESTCAL_CALENDAR_YEARS = Object.freeze(${JSON.stringify(years)});\n`;
fs.writeFileSync(path.join(root, "calendar-years.js"), output, "utf8");
console.log(`Bundled ${Object.keys(years).length} calendar years.`);
